<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Falling Sand Sandbox</title>
  <style>
    :root {
      --bg-color: #121212;
      --card-bg: #1e1e1e;
      --primary: #6200ee;
      --primary-hover: #3700b3;
      --text-color: #e0e0e0;
      --border-color: #333333;
    }

    body {
      margin: 0;
      padding: 0;
      background-color: var(--bg-color);
      color: var(--text-color);
      font-family: 'Roboto', sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      box-sizing: border-box;
    }

    h1 {
      margin: 10px 0;
      font-weight: 400;
      letter-spacing: 1px;
    }

    .container {
      background-color: var(--card-bg);
      padding: 20px;
      border-radius: 8px;
      box-shadow: 0 4px 20px rgba(0,0,0,0.5);
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 15px;
    }

    #sand {
      background-color: #000000;
      border: 2px solid var(--border-color);
      display: block;
      cursor: crosshair;
      image-rendering: pixelated;
      width: 400px;
      height: 400px;
    }

    .controls {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      justify-content: center;
    }

    .btn {
      background-color: #333333;
      color: var(--text-color);
      border: none;
      padding: 10px 16px;
      border-radius: 4px;
      cursor: pointer;
      font-weight: 500;
      text-transform: uppercase;
      font-size: 0.85rem;
      transition: background-color 0.2s, transform 0.1s;
      outline: none;
      user-select: none;
    }

    .btn:hover {
      background-color: #444444;
    }

    .btn:active {
      transform: scale(0.97);
    }

    /* Material Colors for Buttons */
    #mat-sand { border-bottom: 4px solid #e0b034; }
    #mat-sand.active { background-color: #e0b034; color: #000; }

    #mat-water { border-bottom: 4px solid #3b82f6; }
    #mat-water.active { background-color: #3b82f6; color: #fff; }

    #mat-wall { border-bottom: 4px solid #888888; }
    #mat-wall.active { background-color: #888888; color: #fff; }

    #mat-acid { border-bottom: 4px solid #22c55e; }
    #mat-acid.active { background-color: #22c55e; color: #000; }

    #mat-empty { border-bottom: 4px solid #444444; }
    #mat-empty.active { background-color: #ffffff; color: #000; }

    #clear {
      background-color: #b91c1c;
      color: white;
    }
    #clear:hover {
      background-color: #dc2626;
    }

    .instructions {
      font-size: 0.8rem;
      color: #888;
      text-align: center;
      max-width: 400px;
      line-height: 1.4;
    }
  </style>
</head>
<body>

  <div class="container">
    <h1>Sand Sandbox</h1>

    <canvas id="sand" width="100" height="100"></canvas>

    <div class="controls">
      <button id="mat-sand" class="btn active">Sand</button>
      <button id="mat-water" class="btn">Water</button>
      <button id="mat-wall" class="btn">Wall</button>
      <button id="mat-acid" class="btn">Acid</button>
      <button id="mat-empty" class="btn">Eraser</button>
      <button id="clear" class="btn">Clear</button>
    </div>

    <div class="instructions">
      Drag to draw. Sand sinks in liquids. Acid dissolves sand and walls.
    </div>
  </div>

  <script>
    // Configuration
    const WIDTH = 100;
    const HEIGHT = 100;

    // Grid representation: 1D array of strings: "empty" | "sand" | "water" | "wall" | "acid"
    let grid = new Array(WIDTH * HEIGHT).fill("empty");
    // Keep track of whether a cell has updated in the current tick to prevent multi-movement
    let updated = new Uint8Array(WIDTH * HEIGHT);

    // Color mapping for rendering
    const COLORS = {
      empty: [0, 0, 0, 255],
      sand: [224, 176, 52, 255],
      water: [59, 130, 246, 255],
      wall: [136, 136, 136, 255],
      acid: [34, 197, 94, 255]
    };

    // Canvas setup
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d');
    const imgData = ctx.createImageData(WIDTH, HEIGHT);

    // Active material selection
    let currentMaterial = "sand";
    const buttons = {
      sand: document.getElementById('mat-sand'),
      water: document.getElementById('mat-water'),
      wall: document.getElementById('mat-wall'),
      acid: document.getElementById('mat-acid'),
      empty: document.getElementById('mat-empty')
    };

    function selectMaterial(mat) {
      currentMaterial = mat;
      for (const key in buttons) {
        if (key === mat) {
          buttons[key].classList.add('active');
        } else {
          buttons[key].classList.remove('active');
        }
      }
    }

    // Register button listeners
    for (const key in buttons) {
      buttons[key].addEventListener('click', () => selectMaterial(key));
    }

    document.getElementById('clear').addEventListener('click', () => {
      window.sim.clear();
    });

    // Drawing logic
    let isDrawing = false;

    function getMousePos(e) {
      const rect = canvas.getBoundingClientRect();
      const scaleX = WIDTH / rect.width;
      const scaleY = HEIGHT / rect.height;
      const x = Math.floor((e.clientX - rect.left) * scaleX);
      const y = Math.floor((e.clientY - rect.top) * scaleY);
      return { x, y };
    }

    function drawAt(x, y) {
      const radius = currentMaterial === "wall" ? 1 : 3;
      for (let dy = -radius; dy <= radius; dy++) {
        for (let dx = -radius; dx <= radius; dx++) {
          if (dx*dx + dy*dy <= radius*radius) {
            const nx = x + dx;
            const ny = y + dy;
            if (nx >= 0 && nx < WIDTH && ny >= 0 && ny < HEIGHT) {
              // Only overwrite if not wall, or if we are placing wall/eraser
              if (currentMaterial === "wall" || currentMaterial === "empty" || grid[ny * WIDTH + nx] !== "wall") {
                grid[ny * WIDTH + nx] = currentMaterial;
              }
            }
          }
        }
      }
    }

    canvas.addEventListener('mousedown', (e) => {
      isDrawing = true;
      const pos = getMousePos(e);
      drawAt(pos.x, pos.y);
    });

    window.addEventListener('mousemove', (e) => {
      if (isDrawing) {
        const pos = getMousePos(e);
        drawAt(pos.x, pos.y);
      }
    });

    window.addEventListener('mouseup', () => {
      isDrawing = false;
    });

    // Simulation Step
    function tickOnce() {
      updated.fill(0);

      // Process bottom-to-top, left-to-right
      for (let y = HEIGHT - 1; y >= 0; y--) {
        for (let x = 0; x < WIDTH; x++) {
          const idx = y * WIDTH + x;
          if (updated[idx]) continue;

          const mat = grid[idx];
          if (mat === "empty" || mat === "wall") continue;

          if (mat === "sand") {
            // Sand falls straight down
            const below = idx + WIDTH;
            if (y < HEIGHT - 1) {
              const matBelow = grid[below];
              if (matBelow === "empty") {
                grid[below] = "sand";
                grid[idx] = "empty";
                updated[below] = 1;
                continue;
              } else if (matBelow === "water" || matBelow === "acid") {
                // Sinks into liquid: swap
                grid[below] = "sand";
                grid[idx] = matBelow;
                updated[below] = 1;
                continue;
              }
            }

            // Diagonals
            if (y < HEIGHT - 1) {
              const leftFirst = Math.random() < 0.5;
              const dirs = leftFirst ? [-1, 1] : [1, -1];
              let moved = false;

              for (let d of dirs) {
                const nx = x + d;
                if (nx >= 0 && nx < WIDTH) {
                  const targetIdx = below + d;
                  const targetMat = grid[targetIdx];
                  if (targetMat === "empty") {
                    grid[targetIdx] = "sand";
                    grid[idx] = "empty";
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  } else if (targetMat === "water" || targetMat === "acid") {
                    grid[targetIdx] = "sand";
                    grid[idx] = targetMat;
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;
            }
          }

          else if (mat === "water") {
            // Water falls straight down
            const below = idx + WIDTH;
            if (y < HEIGHT - 1 && grid[below] === "empty") {
              grid[below] = "water";
              grid[idx] = "empty";
              updated[below] = 1;
              continue;
            }

            // Diagonals down
            if (y < HEIGHT - 1) {
              const leftFirst = Math.random() < 0.5;
              const dirs = leftFirst ? [-1, 1] : [1, -1];
              let moved = false;
              for (let d of dirs) {
                const nx = x + d;
                if (nx >= 0 && nx < WIDTH) {
                  const targetIdx = below + d;
                  if (grid[targetIdx] === "empty") {
                    grid[targetIdx] = "water";
                    grid[idx] = "empty";
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;
            }

            // Spreads horizontally
            {
              const leftFirst = Math.random() < 0.5;
              const dirs = leftFirst ? [-1, 1] : [1, -1];
              let moved = false;
              for (let d of dirs) {
                const nx = x + d;
                if (nx >= 0 && nx < WIDTH) {
                  const targetIdx = idx + d;
                  if (grid[targetIdx] === "empty") {
                    grid[targetIdx] = "water";
                    grid[idx] = "empty";
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;
            }
          }

          else if (mat === "acid") {
            // Acid dissolves sand/wall below or beside
            let dissolved = false;
            const checkOffsets = [WIDTH, -1, 1]; // below, left, right
            for (let offset of checkOffsets) {
              const targetIdx = idx + offset;
              // Bounds check
              if (offset === WIDTH && y >= HEIGHT - 1) continue;
              if (offset === -1 && x === 0) continue;
              if (offset === 1 && x === WIDTH - 1) continue;

              const targetMat = grid[targetIdx];
              if (targetMat === "sand" || targetMat === "wall") {
                grid[targetIdx] = "empty";
                grid[idx] = "empty";
                dissolved = true;
                break;
              }
            }
            if (dissolved) continue;

            // If not dissolving, move like water
            const below = idx + WIDTH;
            if (y < HEIGHT - 1 && grid[below] === "empty") {
              grid[below] = "acid";
              grid[idx] = "empty";
              updated[below] = 1;
              continue;
            }

            // Diagonals down
            if (y < HEIGHT - 1) {
              const leftFirst = Math.random() < 0.5;
              const dirs = leftFirst ? [-1, 1] : [1, -1];
              let moved = false;
              for (let d of dirs) {
                const nx = x + d;
                if (nx >= 0 && nx < WIDTH) {
                  const targetIdx = below + d;
                  if (grid[targetIdx] === "empty") {
                    grid[targetIdx] = "acid";
                    grid[idx] = "empty";
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;
            }

            // Spreads horizontally
            {
              const leftFirst = Math.random() < 0.5;
              const dirs = leftFirst ? [-1, 1] : [1, -1];
              let moved = false;
              for (let d of dirs) {
                const nx = x + d;
                if (nx >= 0 && nx < WIDTH) {
                  const targetIdx = idx + d;
                  if (grid[targetIdx] === "empty") {
                    grid[targetIdx] = "acid";
                    grid[idx] = "empty";
                    updated[targetIdx] = 1;
                    moved = true;
                    break;
                  }
                }
              }
              if (moved) continue;
            }
          }

        }
      }
    }

    // Render loop
    function render() {
      const data = imgData.data;
      for (let i = 0; i < grid.length; i++) {
        const color = COLORS[grid[i]];
        const rIdx = i * 4;
        data[rIdx] = color[0];
        data[rIdx + 1] = color[1];
        data[rIdx + 2] = color[2];
        data[rIdx + 3] = color[3];
      }
      ctx.putImageData(imgData, 0, 0);
    }

    function loop() {
      tickOnce();
      render();
      requestAnimationFrame(loop);
    }

    // Programmatic API
    window.sim = {
      w: WIDTH,
      h: HEIGHT,
      tick(n) {
        for (let i = 0; i < n; i++) {
          tickOnce();
        }
        render();
      },
      get(x, y) {
        if (x < 0 || x >= WIDTH || y < 0 || y >= HEIGHT) return "empty";
        return grid[y * WIDTH + x];
      },
      set(x, y, material) {
        if (x >= 0 && x < WIDTH && y >= 0 && y < HEIGHT) {
          grid[y * WIDTH + x] = material;
          render();
        }
      },
      clear() {
        grid.fill("empty");
        render();
      }
    };

    // Start simulation
    render();
    requestAnimationFrame(loop);
  </script>
</body>
</html>
